form:Form.form:Scripts:
		function DisableControls()
{
	Ctrl('oi_provincia_ALL').SetEnabled(false);
	Ctrl('oi_localidad_ALL').SetEnabled(false);
}

function EnableControl()
{
	if (Ctrl('c_tipo_lib').GetXValue() == 'LOC')
	{
		//Ctrl('oi_provincia').SetXValue('');
		Ctrl('oi_provincia_ALL').Clear();
		Ctrl('oi_localidad_ALL').SetEnabled(true);
		Ctrl('oi_provincia_ALL').SetEnabled(false);	
		return true;
	}
	else if (Ctrl('c_tipo_lib').GetXValue() == 'PRO')
	{		
		//Ctrl('oi_localidad').SetXValue('');
		Ctrl('oi_localidad_ALL').Clear();
		Ctrl('oi_localidad_ALL').SetEnabled(false);
		Ctrl('oi_provincia_ALL').SetEnabled(true);
		return true;
	}    
	else
	{		
		//Ctrl('oi_provincia').SetXValue('');
		//Ctrl('oi_localidad').SetXValue('');
		Ctrl('oi_provincia_ALL').Clear();
		Ctrl('oi_localidad_ALL').Clear();
		Ctrl('oi_provincia_ALL').SetEnabled(false);
		Ctrl('oi_localidad_ALL').SetEnabled(false);
	}
	return true;
}

function ValidateData(myThis)
{
	if (Ctrl('oi_localidad').GetXValue() == '' && Ctrl('c_tipo_lib').GetXValue() == 'LOC')
	{
		myThis.SetError('Se requiere una Localidad para el Tipo de Libreta ingresado');					
		return false;
	}
	if (Ctrl('oi_provincia').GetXValue() == '' && Ctrl('c_tipo_lib').GetXValue() == 'PRO')
	{
		myThis.SetError('Se requiere una Provincia para el Tipo de Libreta ingresado');		
		return false;
	}
	else return true;
}
